  ('dietitian-moex-04235', 'dietitian', 'dietitian-moex-113-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '依據母嬰親善醫院認證所提的產科機構應該要有哺餵母乳的措施，下列敘述何者錯誤？', '["提供每天8小時的母嬰同室", "鼓勵依嬰兒的需求哺餵母乳", "教導母親哺餵母乳，及在必須和嬰兒分開的情況下如何維持奶水的分泌", "哺餵母乳的嬰兒，不給予人工奶嘴或安撫奶嘴"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:34+00:00", "source_pdf_sha1": "cfe2ad5d83fc", "answer_pdf_sha1": "e5ac6dfb7c17", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
